function getReasonGroup(reason){
  return REASON_GROUPS.find(g=>g.reasons.some(r=>r.v===reason))||null;
}
function getReasonDesc(reason){
  for(const g of REASON_GROUPS){ const r=g.reasons.find(r=>r.v===reason); if(r) return r.d; }
  return '';
}
