/* BEGIN: modules/main/persistence/05b-cloud-bootstrap-and-schedule.js */
// ============================================================
// Cloud bootstrap / schedule policy helpers
// ============================================================

function getDefaultCloudMeta() {
  return {
    restoreDecisions: {},
    lastSeenBackupAt: '',
    lastIncrementalAlignedAt: '',
    lastLoadedAt: '',
    lastSavedAt: '',
    lastLocalChangeAt: '',
    lastMetaCheckAt: '',
    lastIncrementalSyncAt: '',
    nextCloudSaveAt: '',
    nextIncrementalSyncAt: ''
  };
}

function saveCloudMeta() {
  DB.set(KEY_CLOUD_META, JSON.stringify(cloudMeta || getDefaultCloudMeta()));
}

function getIsoAgeMs(isoText) {
  const value = Date.parse(String(isoText || '').trim());
  if (!Number.isFinite(value)) return Number.POSITIVE_INFINITY;
  return Math.max(0, Date.now() - value);
}

function markCloudMetaChecked(at) {
  if (!cloudMeta || typeof cloudMeta !== 'object') cloudMeta = getDefaultCloudMeta();
  cloudMeta.lastMetaCheckAt = String(at || new Date().toISOString());
  saveCloudMeta();
}

function markIncrementalSyncChecked(at) {
  if (!cloudMeta || typeof cloudMeta !== 'object') cloudMeta = getDefaultCloudMeta();
  const value = String(at || new Date().toISOString());
  cloudMeta.lastIncrementalSyncAt = value;
  cloudMeta.lastIncrementalAlignedAt = value;
  saveCloudMeta();
}

function setNextCloudSaveAt(at) {
  if (!cloudMeta || typeof cloudMeta !== 'object') cloudMeta = getDefaultCloudMeta();
  cloudMeta.nextCloudSaveAt = String(at || '');
  saveCloudMeta();
}

function setNextIncrementalSyncAt(at) {
  if (!cloudMeta || typeof cloudMeta !== 'object') cloudMeta = getDefaultCloudMeta();
  cloudMeta.nextIncrementalSyncAt = String(at || '');
  saveCloudMeta();
}

function isManualCloudSyncOnly() {
  return CLOUD_MANUAL_SYNC_ONLY;
}

function scheduleDeferredSlowSync() {
  if (isManualCloudSyncOnly()) return;
  const dueAt = new Date(Date.now() + AUTO_SYNC_DELAY_MS).toISOString();
  setNextIncrementalSyncAt(dueAt);
  if (incrementalSyncTimer) clearTimeout(incrementalSyncTimer);
  incrementalSyncTimer = setTimeout(() => {
    incrementalSyncTimer = null;
    syncWithServer({ forceFullPull: true });
  }, AUTO_SYNC_DELAY_MS);
}

function isScheduledAtDue(isoText) {
  const value = Date.parse(String(isoText || '').trim());
  if (!Number.isFinite(value)) return false;
  return Date.now() >= value;
}

function shouldRunCloudSaveDue() {
  return Boolean(cloudMeta && cloudMeta.nextCloudSaveAt) && isScheduledAtDue(cloudMeta.nextCloudSaveAt);
}

function shouldUseIncrementalOnlyAutoSave() {
  const summary = startupSummaryCache || {};
  const bytes = Number(summary.errorsBytes || 0);
  if (bytes >= INCREMENTAL_ONLY_AUTO_SAVE_BYTES) return true;
  return isLikelyMobileLikeDevice() && bytes >= MOBILE_DEFERRED_RESTORE_BYTES;
}

function shouldRunIncrementalSyncDue() {
  return Boolean(cloudMeta && cloudMeta.nextIncrementalSyncAt) && isScheduledAtDue(cloudMeta.nextIncrementalSyncAt);
}

function hasPendingIncrementalOps() {
  return getPendingOps().length > 0;
}

function shouldCheckCloudMetaOnStartup() {
  if (!hasLocalWorkspaceData()) return true;
  return getIsoAgeMs(cloudMeta && cloudMeta.lastMetaCheckAt) >= STARTUP_CLOUD_META_TTL_MS;
}

function shouldRunIncrementalSyncOnStartup() {
  if (hasPendingIncrementalOps()) return shouldRunIncrementalSyncDue();
  return getIsoAgeMs(cloudMeta && cloudMeta.lastIncrementalSyncAt) >= STARTUP_INCREMENTAL_SYNC_TTL_MS;
}

function shouldCheckCloudMetaInForeground() {
  if (!hasLocalWorkspaceData()) return true;
  return getIsoAgeMs(cloudMeta && cloudMeta.lastMetaCheckAt) >= FOREGROUND_CLOUD_CHECK_TTL_MS;
}

function shouldRunIncrementalSyncInForeground() {
  if (hasPendingIncrementalOps()) return shouldRunIncrementalSyncDue();
  return getIsoAgeMs(cloudMeta && cloudMeta.lastIncrementalSyncAt) >= FOREGROUND_CLOUD_CHECK_TTL_MS;
}

async function runBackgroundCloudBootstrap(strategy) {
  if (isManualCloudSyncOnly()) {
    renderCloudUi();
    return;
  }
  const run = async () => {
    if (!cloudUser) return;
    try {
      const mode = String(strategy || 'startup');
      const checkMeta = mode === 'startup' ? shouldCheckCloudMetaOnStartup() : shouldCheckCloudMetaInForeground();
      const checkIncremental = mode === 'startup' ? shouldRunIncrementalSyncOnStartup() : shouldRunIncrementalSyncInForeground();
      const checkCloudSave = shouldRunCloudSaveDue();
      const incrementalOnlyAutoSave = shouldUseIncrementalOnlyAutoSave();
      if (checkMeta) {
        await maybeRestoreCloudBackup();
      }
      if (checkCloudSave) {
        if (incrementalOnlyAutoSave) {
          setNextCloudSaveAt('');
          await syncWithServer();
        } else {
          await saveCloudBackup({ silent: true });
        }
      } else if (checkIncremental) {
        await syncWithServer();
      }
    } finally {
      renderCloudUi();
      if (pendingCloudSave) {
        pendingCloudSave = false;
        scheduleCloudSave();
      }
    }
  };
  return run();
}

function scheduleBackgroundCloudBootstrap(strategy) {
  if (isManualCloudSyncOnly()) return;
  const run = () => { runBackgroundCloudBootstrap(strategy); };
  if (typeof window.requestIdleCallback === 'function') {
    window.requestIdleCallback(() => { run(); }, { timeout: 1200 });
    return;
  }
  setTimeout(() => { run(); }, 120);
}

function scheduleForegroundCloudWakeCheck() {
  if (isManualCloudSyncOnly()) return;
  if (backgroundCloudBootstrapTimer) clearTimeout(backgroundCloudBootstrapTimer);
  backgroundCloudBootstrapTimer = setTimeout(() => {
    backgroundCloudBootstrapTimer = null;
    scheduleBackgroundCloudBootstrap('foreground');
  }, 180);
}
/* END: modules/main/persistence/05b-cloud-bootstrap-and-schedule.js */

/* BEGIN: modules/main/persistence/05c-cloud-restore-origin-utils.js */
// ============================================================
// Cloud restore and origin status utility helpers
// ============================================================

function getCloudBackupBytes(meta) {
  return Number(meta && meta.payloadBytes || 0);
}

function formatBackupBytes(bytes) {
  const value = Number(bytes || 0);
  if (!value) return '0 B';
  if (value >= 1024 * 1024) return `${(value / (1024 * 1024)).toFixed(1)} MB`;
  if (value >= 1024) return `${Math.round(value / 1024)} KB`;
  return `${value} B`;
}

function isLikelyMobileClient() {
  const ua = String((navigator && navigator.userAgent) || '').toLowerCase();
  return /android|iphone|ipad|ipod|mobile|harmony/.test(ua);
}

function shouldUseDeferredCloudRestore(meta) {
  const bytes = getCloudBackupBytes(meta);
  if (!bytes) return false;
  if (bytes >= LARGE_CLOUD_BACKUP_BYTES) return true;
  return isLikelyMobileClient() && bytes >= MOBILE_DEFERRED_RESTORE_BYTES;
}

function delayCloudRestore(ms) {
  return new Promise(resolve => setTimeout(resolve, ms || 0));
}

function getBackupSummary(meta) {
  const summary = meta && typeof meta.summary === 'object' ? meta.summary : {};
  return {
    errors: Number(summary.errors || 0),
    notesByType: Number(summary.notesByType || 0),
    noteImages: Number(summary.noteImages || 0),
    knowledgeNodes: Number(summary.knowledgeNodes || 0),
    knowledgeNotes: Number(summary.knowledgeNotes || 0)
  };
}

function getLocalWorkspaceSummary() {
  return {
    errors: getErrorEntries().length,
    notesByType: Object.keys(notesByType || {}).length,
    noteImages: Object.keys(noteImages || {}).length,
    knowledgeNodes: typeof collectKnowledgeNodes === 'function' ? collectKnowledgeNodes().length : 0,
    knowledgeNotes: Object.keys(knowledgeNotes || {}).length
  };
}

function isSameBackupSummary(left, right) {
  const a = left || {};
  const b = right || {};
  return ['errors', 'notesByType', 'noteImages', 'knowledgeNodes', 'knowledgeNotes']
    .every(key => Number(a[key] || 0) === Number(b[key] || 0));
}

async function clearWorkspaceStorageForRemoteRestore() {
  const keys = [
    KEY_ERRORS, KEY_REVEALED, KEY_EXP_TYPES, KEY_EXP_MAIN, KEY_EXP_SUB2,
    KEY_GLOBAL_NOTE, KEY_TODAY_DATE, KEY_TODAY_DONE, KEY_HISTORY,
    KEY_TYPE_RULES, KEY_NOTES_BY_TYPE, KEY_NOTE_IMAGES,
    KEY_DIR_TREE, KEY_KNOWLEDGE_TREE, KEY_KNOWLEDGE_NOTES
  ];
  await Promise.all(keys.map(key => DB.remove(key)));
  ['lastSyncCursorAt', 'lastSyncCursorId'].forEach(key => {
    try { localStorage.removeItem(key); } catch (e) {}
  });
}

function clearLocalSyncMarkers() {
  ['lastSyncCursorAt', 'lastSyncCursorId'].forEach(key => {
    try { localStorage.removeItem(key); } catch (e) {}
  });
  setErrorSyncSnapshot(new Map());
  setWorkspaceSyncSnapshot(new Map());
}

function resetCurrentOriginRestoreDecision() {
  if (!cloudMeta || typeof cloudMeta !== 'object') cloudMeta = getDefaultCloudMeta();
  const key = getCloudOriginKey();
  if (cloudMeta.restoreDecisions && cloudMeta.restoreDecisions[key]) {
    delete cloudMeta.restoreDecisions[key];
    saveCloudMeta();
  }
}

function getCloudOriginKey() {
  return (window.location && window.location.origin) ? window.location.origin : 'origin:unknown';
}

function isLocalDebugOrigin(origin) {
  const text = String(origin || '').toLowerCase();
  return text.includes('127.0.0.1') || text.includes('localhost');
}

function normalizeCloudIso(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  const parsed = Date.parse(text);
  if (!Number.isFinite(parsed)) return '';
  return new Date(parsed).toISOString();
}

function formatCloudTime(value) {
  const iso = normalizeCloudIso(value);
  if (!iso) return '-';
  const date = new Date(iso);
  const local = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')} ${String(date.getHours()).padStart(2, '0')}:${String(date.getMinutes()).padStart(2, '0')}`;
  return local;
}

function toCloudTimeMs(value) {
  const iso = normalizeCloudIso(value);
  if (!iso) return 0;
  return Date.parse(iso) || 0;
}

function getOriginDisplayTime(item) {
  const latest = item && item.lastSyncedAt ? item.lastSyncedAt : (item && item.updatedAt ? item.updatedAt : '');
  return formatCloudTime(latest);
}

function mergeCurrentOriginStatus() {
  const key = getCloudOriginKey();
  const statuses = Array.isArray(cloudOriginStatuses) ? cloudOriginStatuses.slice() : [];
  let current = statuses.find(item => item && item.origin === key) || null;
  if (!current) {
    current = {
      origin: key,
      originLabel: key,
      status: cloudSyncState,
      updatedAt: cloudSyncUpdatedAt || new Date().toISOString(),
      payloadBytes: 0
    };
    statuses.push(current);
  }
  cloudOriginStatuses = statuses;
  return current;
}

function updateCloudOriginStatuses(items) {
  cloudOriginStatuses = Array.isArray(items) ? items.slice() : [];
}

async function pushOriginStatus(update) {
  if (!cloudUser) return;
  try {
    const body = {
      origin: getCloudOriginKey(),
      status: update && update.status ? String(update.status) : cloudSyncState,
      updatedAt: normalizeCloudIso(update && update.updatedAt ? update.updatedAt : cloudSyncUpdatedAt) || new Date().toISOString(),
      payloadBytes: Number(update && update.payloadBytes || 0),
      summary: update && update.summary ? update.summary : undefined
    };
    await fetchJsonWithAuth('/api/cloud/origin-status', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
  } catch (e) {
    console.warn('push origin status failed', e);
  }
}

function scheduleOriginStatusSync(update) {
  if (cloudOriginStatusTimer) clearTimeout(cloudOriginStatusTimer);
  cloudOriginStatusTimer = setTimeout(() => {
    cloudOriginStatusTimer = null;
    pushOriginStatus(update);
  }, 120);
}

function markLocalChange() {
  if (!cloudMeta || typeof cloudMeta !== 'object') cloudMeta = getDefaultCloudMeta();
  cloudMeta.lastLocalChangeAt = new Date().toISOString();
  saveCloudMeta();
}

function setCloudSyncState(state, message, at) {
  cloudSyncState = String(state || 'idle');
  cloudSyncMessage = String(message || '');
  cloudSyncUpdatedAt = normalizeCloudIso(at) || (cloudSyncState === 'idle' ? '' : new Date().toISOString());
  renderCloudUi();
}

function hasLocalWorkspaceData() {
  return getErrorEntries().length > 0
    || Object.keys(notesByType || {}).length > 0
    || Object.keys(noteImages || {}).length > 0
    || Object.keys(knowledgeNotes || {}).length > 0
    || (typeof collectKnowledgeNodes === 'function' && collectKnowledgeNodes().length > 0)
    || (_history && _history.length > 0)
    || !!(globalNote || '').trim();
}

function rememberCloudDecision(updatedAt, action) {
  if (!cloudMeta || typeof cloudMeta !== 'object') cloudMeta = getDefaultCloudMeta();
  if (!cloudMeta.restoreDecisions || typeof cloudMeta.restoreDecisions !== 'object') {
    cloudMeta.restoreDecisions = {};
  }
  cloudMeta.restoreDecisions[getCloudOriginKey()] = {
    updatedAt: normalizeCloudIso(updatedAt) || '',
    action: String(action || ''),
    decidedAt: new Date().toISOString()
  };
  saveCloudMeta();
}
/* END: modules/main/persistence/05c-cloud-restore-origin-utils.js */

/* BEGIN: modules/main/persistence/05d-local-backup-ui.js */
// ============================================================
// Local backup UI and restore controls
// ============================================================

const KEY_LOCAL_BACKUP_LAST_AUTO_DAY = 'xc_local_backup_last_auto_day';

const LOCAL_BACKUP_STATUS_STYLE = {
  info: '#667085',
  success: '#067647',
  warning: '#b54708',
  error: '#b42318'
};

const localBackupUiState = {
  list: [],
  busy: false,
  busyAction: '',
  busyBackupId: '',
  message: '',
  tone: 'info',
  listBound: false
};

function escapeLocalBackupText(value) {
  return escapeHtml(String(value == null ? '' : value));
}

function formatLocalBackupSize(bytes) {
  const size = Number(bytes || 0);
  if (!size) return '0 B';
  if (size >= 1024 * 1024) return `${(size / (1024 * 1024)).toFixed(1)} MB`;
  if (size >= 1024) return `${Math.round(size / 1024)} KB`;
  return `${size} B`;
}

function formatLocalBackupTime(value) {
  const text = String(value || '').trim();
  if (!text) return '-';
  const stamp = Date.parse(text);
  if (!Number.isFinite(stamp)) return text;
  const d = new Date(stamp);
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')} ${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`;
}

function backupKindLabel(kind) {
  const value = String(kind || '');
  if (value === 'auto') return '自动备份';
  if (value === 'manual') return '手动备份';
  if (value === 'before_restore') return '恢复前安全备份';
  return value || '备份';
}

function getLocalBackupSummaryText(items) {
  const list = Array.isArray(items) ? items : [];
  const totalSize = list.reduce((sum, item) => sum + Number((item && item.sizeBytes) || 0), 0);
  return `共 ${list.length} 份备份，合计 ${formatLocalBackupSize(totalSize)}。自动备份只保留最新 1 份。`;
}

function setLocalBackupStatus(message, tone) {
  const summaryEl = document.getElementById('localBackupSummary');
  localBackupUiState.message = String(message || '');
  localBackupUiState.tone = String(tone || 'info');
  if (!summaryEl) return;
  summaryEl.textContent = localBackupUiState.message || getLocalBackupSummaryText(localBackupUiState.list);
  summaryEl.style.color = LOCAL_BACKUP_STATUS_STYLE[localBackupUiState.tone] || LOCAL_BACKUP_STATUS_STYLE.info;
}

function setLocalBackupBusy(busy, action, backupId) {
  localBackupUiState.busy = !!busy;
  localBackupUiState.busyAction = busy ? String(action || '') : '';
  localBackupUiState.busyBackupId = busy ? String(backupId || '') : '';
}

function syncLocalBackupButtons() {
  const listEl = document.getElementById('localBackupList');
  if (!listEl) return;
  listEl.querySelectorAll('button[data-local-backup-action]').forEach((btn) => {
    const action = btn.getAttribute('data-local-backup-action') || '';
    const backupId = btn.getAttribute('data-backup-id') || '';
    const label = btn.getAttribute('data-label-default') || btn.textContent || '';
    const isBusy = !!localBackupUiState.busy;
    const isCurrent = isBusy
      && localBackupUiState.busyAction === action
      && localBackupUiState.busyBackupId === backupId;
    const disableForBusy = isBusy && action !== 'download';
    btn.disabled = disableForBusy;
    btn.style.opacity = disableForBusy ? '0.65' : '';
    btn.style.cursor = disableForBusy ? 'not-allowed' : '';
    if (isCurrent && action === 'restore') {
      btn.textContent = '恢复中...';
    } else if (isCurrent && action === 'delete') {
      btn.textContent = '删除中...';
    } else {
      btn.textContent = label;
    }
  });

  document.querySelectorAll('#localBackupModal [data-local-backup-global]').forEach((btn) => {
    const action = btn.getAttribute('data-local-backup-global') || '';
    const label = btn.getAttribute('data-label-default') || btn.textContent || '';
    const isBusy = !!localBackupUiState.busy;
    btn.disabled = isBusy;
    btn.style.opacity = isBusy ? '0.65' : '';
    btn.style.cursor = isBusy ? 'not-allowed' : '';
    btn.textContent = isBusy && action === 'create' ? '备份中...' : label;
  });
}

function ensureLocalBackupListBinding() {
  const listEl = document.getElementById('localBackupList');
  if (!listEl || localBackupUiState.listBound) return;
  listEl.addEventListener('click', (event) => {
    const target = event.target instanceof Element ? event.target.closest('button[data-local-backup-action]') : null;
    if (!target || target.disabled) return;
    const action = String(target.getAttribute('data-local-backup-action') || '').trim();
    const backupId = String(target.getAttribute('data-backup-id') || '').trim();
    if (!action || !backupId) return;
    event.preventDefault();
    event.stopPropagation();
    if (action === 'download') {
      downloadLocalBackupById(backupId);
      return;
    }
    if (action === 'restore') {
      void restoreLocalBackupById(backupId);
      return;
    }
    if (action === 'delete') {
      void deleteLocalBackupById(backupId);
    }
  });
  localBackupUiState.listBound = true;
}

function ensureLocalBackupMenuButton() {
  const panel = document.getElementById('moreMenuPanel');
  if (!panel) return;
  if (panel.querySelector('[data-onclick*="openLocalBackupModalFromMore"]')) return;
  const cloudSaveBtn = panel.querySelector('[data-onclick*="saveCloudFullBackupFromMore"]');
  const btn = document.createElement('button');
  btn.className = 'btn btn-secondary';
  btn.setAttribute('data-onclick', 'openLocalBackupModalFromMore()');
  btn.textContent = '备份数据列表';
  if (cloudSaveBtn && cloudSaveBtn.nextSibling) {
    cloudSaveBtn.insertAdjacentElement('afterend', btn);
  } else {
    panel.appendChild(btn);
  }
}

async function openLocalBackupModalFromMore() {
  if (typeof closeMoreMenu === 'function') closeMoreMenu();
  if (typeof ensureDeferredPartialsLoaded === 'function') {
    try { await ensureDeferredPartialsLoaded(); } catch (e) {}
  }
  if (typeof ensureLegacyModalBundleLoaded === 'function') {
    try { await ensureLegacyModalBundleLoaded(); } catch (e) {}
  }
  if (typeof openModal === 'function') {
    openModal('localBackupModal');
  } else {
    const modal = document.getElementById('localBackupModal');
    if (modal) modal.style.display = 'flex';
  }
  ensureLocalBackupListBinding();
  await refreshLocalBackups();
}

function renderLocalBackupList(items) {
  const listEl = document.getElementById('localBackupList');
  if (!listEl) return;

  const list = Array.isArray(items) ? items.slice() : [];
  localBackupUiState.list = list;

  if (!localBackupUiState.message || localBackupUiState.tone === 'info') {
    setLocalBackupStatus(getLocalBackupSummaryText(list), localBackupUiState.tone || 'info');
  }

  if (!list.length) {
    listEl.innerHTML = '<div style="font-size:12px;color:#94a3b8;border:1px dashed #d1d5db;border-radius:10px;padding:12px">暂无本地备份</div>';
    syncLocalBackupButtons();
    return;
  }

  listEl.innerHTML = list.map((item) => {
    const id = String((item && item.id) || '');
    const summary = item && typeof item.summary === 'object' ? item.summary : {};
    const label = String((item && item.label) || '');
    const title = label ? `${backupKindLabel(item && item.kind)} · ${label}` : backupKindLabel(item && item.kind);
    const backupArg = escapeLocalBackupText(id);
    return `
      <div style="border:1px solid #e5e7eb;border-radius:12px;padding:10px 12px;margin-bottom:10px;background:#fff">
        <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start;flex-wrap:wrap">
          <div>
            <div style="font-weight:600;color:#111827">${escapeLocalBackupText(title)}</div>
            <div style="font-size:12px;color:#667085;margin-top:4px">
              时间：${escapeLocalBackupText(formatLocalBackupTime(item && item.createdAt))} · 大小：${escapeLocalBackupText(formatLocalBackupSize(item && item.sizeBytes))}
            </div>
            <div style="font-size:12px;color:#667085;margin-top:2px">
              错题 ${Number(summary.errors || 0)} · 笔记 ${Number(summary.notesByType || 0)} · 知识点 ${Number(summary.knowledgeNodes || 0)}
            </div>
          </div>
          <div style="display:flex;gap:6px;flex-wrap:wrap">
            <button class="btn btn-secondary btn-sm" type="button" data-local-backup-action="download" data-backup-id="${backupArg}" data-label-default="下载到本地">下载到本地</button>
            <button class="btn btn-secondary btn-sm" type="button" data-local-backup-action="restore" data-backup-id="${backupArg}" data-label-default="恢复备份">恢复备份</button>
            <button class="btn btn-secondary btn-sm" type="button" data-local-backup-action="delete" data-backup-id="${backupArg}" data-label-default="删除" style="color:#b42318;border-color:#fda29b">删除</button>
          </div>
        </div>
      </div>
    `;
  }).join('');

  syncLocalBackupButtons();
}

async function refreshLocalBackups() {
  setLocalBackupStatus('正在加载备份列表...', 'info');
  try {
    const data = await fetchJsonWithAuth('/api/local-backups', { method: 'GET' });
    localBackupUiState.message = '';
    localBackupUiState.tone = 'info';
    renderLocalBackupList(data && data.items ? data.items : []);
  } catch (error) {
    setLocalBackupStatus('加载失败，请稍后重试', 'error');
    showToast(`加载本地备份失败：${(error && error.message) || 'unknown error'}`, 'error');
  }
}

async function createLocalBackupByKind(kind, label, opts) {
  const options = opts || {};
  const skipRecentHours = Number(options.skipRecentHours || 0);
  const silent = !!options.silent;
  const data = await fetchJsonWithAuth('/api/local-backups/create', {
    method: 'POST',
    body: {
      kind: String(kind || 'manual'),
      label: String(label || ''),
      skipRecentHours: skipRecentHours > 0 ? skipRecentHours : 0
    }
  });

  if (document.getElementById('localBackupModal')) {
    localBackupUiState.message = '';
    localBackupUiState.tone = 'info';
    renderLocalBackupList(data && data.items ? data.items : []);
  }

  if (!silent) {
    if (data && data.created) {
      setLocalBackupStatus('手动备份已创建成功。', 'success');
      showToast(`${backupKindLabel(kind)}已创建`, 'success');
    } else if (data && data.skipped) {
      setLocalBackupStatus('本次自动备份已跳过，因为近期已经创建过备份。', 'warning');
      showToast(`${backupKindLabel(kind)}跳过（时间间隔未到）`, 'warning');
    }
  }

  return data;
}

async function createManualLocalBackup() {
  setLocalBackupBusy(true, 'create', '');
  setLocalBackupStatus('正在创建手动备份...', 'info');
  syncLocalBackupButtons();
  try {
    await createLocalBackupByKind('manual', '手动备份', { skipRecentHours: 0, silent: false });
  } catch (error) {
    setLocalBackupStatus(`手动备份失败：${(error && error.message) || 'unknown error'}`, 'error');
    showToast(`手动备份失败：${(error && error.message) || 'unknown error'}`, 'error');
  } finally {
    setLocalBackupBusy(false, '', '');
    syncLocalBackupButtons();
  }
}

function downloadLocalBackupById(backupId) {
  const id = String(backupId || '').trim();
  if (!id) return;
  const url = `/api/local-backups/${encodeURIComponent(id)}/download`;
  const link = document.createElement('a');
  link.href = url;
  link.target = '_blank';
  link.rel = 'noopener';
  document.body.appendChild(link);
  link.click();
  link.remove();
  setLocalBackupStatus(`已开始下载备份 ${id}，浏览器会保存为 tar.gz 文件。`, 'success');
}

async function restoreLocalBackupById(backupId) {
  const id = String(backupId || '').trim();
  if (!id) return;
  const ok = confirm('恢复该备份会覆盖当前数据，恢复前会自动创建一份安全备份，确认继续？');
  if (!ok) return;

  setLocalBackupBusy(true, 'restore', id);
  setLocalBackupStatus(`正在恢复备份 ${id}，请稍候...`, 'warning');
  syncLocalBackupButtons();

  try {
    const restoreData = await fetchJsonWithAuth('/api/local-backups/restore', {
      method: 'POST',
      body: { backupId: id, createSafetyBackup: true }
    });
    const restoredBackup = restoreData && restoreData.backup ? restoreData.backup : null;
    if (!restoredBackup) {
      throw new Error('restored snapshot payload missing after restore');
    }
    await applyCloudBackup(
      { ...restoredBackup, summary: restoreData.summary || restoredBackup.summary || {} },
      restoreData.updatedAt || restoredBackup.exportTime || '',
      {
        silent: true,
        forceOverwriteLocal: true,
        staged: true,
        skipCompletionAlert: true
      }
    );
    if (typeof refreshWorkspaceAfterKnowledgeDataChange === 'function') {
      refreshWorkspaceAfterKnowledgeDataChange({ sidebar: true, notes: true, rightPanel: true });
    } else {
      if (typeof invalidateKnowledgeTreeRenderState === 'function') invalidateKnowledgeTreeRenderState();
      renderSidebar();
      renderAll();
      renderNotesByType();
      if (typeof renderNotesPanelRight === 'function') renderNotesPanelRight();
    }
    await refreshLocalBackups();
    setLocalBackupStatus(`恢复成功：已切回备份 ${id}，本地数据已刷新。`, 'success');
    showToast('本地备份恢复成功，本地数据已刷新', 'success');
  } catch (error) {
    setLocalBackupStatus(`恢复失败：${(error && error.message) || 'unknown error'}`, 'error');
    showToast(`恢复失败：${(error && error.message) || 'unknown error'}`, 'error');
  } finally {
    setLocalBackupBusy(false, '', '');
    syncLocalBackupButtons();
  }
}

async function deleteLocalBackupById(backupId) {
  const id = String(backupId || '').trim();
  if (!id) return;
  if (!confirm('确认删除这份本地备份？')) return;

  setLocalBackupBusy(true, 'delete', id);
  setLocalBackupStatus(`正在删除备份 ${id}...`, 'warning');
  syncLocalBackupButtons();

  try {
    const data = await fetchJsonWithAuth(`/api/local-backups/${encodeURIComponent(id)}`, { method: 'DELETE' });
    localBackupUiState.message = '';
    localBackupUiState.tone = 'info';
    renderLocalBackupList(data && data.items ? data.items : []);
    setLocalBackupStatus(`删除成功：备份 ${id} 已移除。`, 'success');
    showToast('本地备份已删除', 'success');
  } catch (error) {
    setLocalBackupStatus(`删除失败：${(error && error.message) || 'unknown error'}`, 'error');
    showToast(`删除失败：${(error && error.message) || 'unknown error'}`, 'error');
  } finally {
    setLocalBackupBusy(false, '', '');
    syncLocalBackupButtons();
  }
}

async function ensureDailyLocalBackup() {
  const todayKey = today();
  try {
    const last = localStorage.getItem(KEY_LOCAL_BACKUP_LAST_AUTO_DAY) || '';
    if (last === todayKey) return;
  } catch (e) {}
  try {
    await createLocalBackupByKind('auto', '每日自动备份', {
      skipRecentHours: 20,
      silent: true
    });
    try { localStorage.setItem(KEY_LOCAL_BACKUP_LAST_AUTO_DAY, todayKey); } catch (e) {}
  } catch (error) {
    console.warn('daily local backup failed', error);
  }
}

window.ensureLocalBackupMenuButton = ensureLocalBackupMenuButton;
window.openLocalBackupModalFromMore = openLocalBackupModalFromMore;
window.refreshLocalBackups = refreshLocalBackups;
window.createManualLocalBackup = createManualLocalBackup;
window.downloadLocalBackupById = downloadLocalBackupById;
window.restoreLocalBackupById = restoreLocalBackupById;
window.deleteLocalBackupById = deleteLocalBackupById;
window.ensureDailyLocalBackup = ensureDailyLocalBackup;
/* END: modules/main/persistence/05d-local-backup-ui.js */

